import React, { useState, useEffect, useCallback } from 'react';
import { BrowserRouter as Router, Route, Routes, useNavigate, useLocation } from 'react-router-dom';

// --- OIDC Configuration ---
// Replace with your actual OIDC provider details
const OIDC_CONFIG = {
  ISSUER: 'YOUR_OIDC_ISSUER_URL', // e.g., 'https://dev-XXXXXX.okta.com/oauth2/default'
  CLIENT_ID: 'YOUR_OIDC_CLIENT_ID',
  REDIRECT_URI: window.location.origin + '/callback',
  AUTHORIZATION_ENDPOINT: 'YOUR_OIDC_AUTHORIZATION_ENDPOINT', // e.g., 'https://dev-XXXXXX.okta.com/oauth2/default/v1/authorize'
  TOKEN_ENDPOINT: 'YOUR_OIDC_TOKEN_ENDPOINT', // e.g., 'https://dev-XXXXXX.okta.com/oauth2/default/v1/token'
  SCOPE: 'openid profile email',
};

// --- Utility Functions ---
const generateRandomString = (length) => {
  const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let result = '';
  for (let i = 0; i < length; i++) {
    result += characters.charAt(Math.floor(Math.random() * characters.length));
  }
  return result;
};

const decodeJwt = (token) => {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(atob(base64).split('').map(function(c) {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
    return JSON.parse(jsonPayload);
  } catch (e) {
    console.error("Failed to decode JWT:", e);
    return null;
  }
};

// --- Auth Context (for global state management) ---
const AuthContext = React.createContext(null);

const AuthProvider = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userProfile, setUserProfile] = useState(null);
  const [idToken, setIdToken] = useState(null);
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    // Attempt to load auth state from localStorage on mount
    const storedIdToken = localStorage.getItem('id_token');
    const storedAccessToken = localStorage.getItem('access_token');
    const storedUserProfile = localStorage.getItem('user_profile');

    if (storedIdToken && storedAccessToken && storedUserProfile) {
      setIdToken(storedIdToken);
      setAccessToken(storedAccessToken);
      setUserProfile(JSON.parse(storedUserProfile));
      setIsAuthenticated(true);
    }
  }, []);

  const login = useCallback((id_token, access_token, profile) => {
    setIdToken(id_token);
    setAccessToken(access_token);
    setUserProfile(profile);
    setIsAuthenticated(true);
    localStorage.setItem('id_token', id_token);
    localStorage.setItem('access_token', access_token);
    localStorage.setItem('user_profile', JSON.stringify(profile));
  }, []);

  const logout = useCallback(() => {
    setIdToken(null);
    setAccessToken(null);
    setUserProfile(null);
    setIsAuthenticated(false);
    localStorage.removeItem('id_token');
    localStorage.removeItem('access_token');
    localStorage.removeItem('user_profile');
    localStorage.removeItem('oidc_state'); // Clear state used for callback
    localStorage.removeItem('oidc_nonce'); // Clear nonce used for callback
  }, []);

  const authContextValue = {
    isAuthenticated,
    userProfile,
    idToken,
    accessToken,
    login,
    logout,
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      {children}
    </AuthContext.Provider>
  );
};

// --- Components ---

const Home = () => {
  const { isAuthenticated, userProfile, logout } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleLoginRedirect = () => {
    const state = generateRandomString(32);
    const nonce = generateRandomString(32);

    localStorage.setItem('oidc_state', state);
    localStorage.setItem('oidc_nonce', nonce);

    const authUrl = new URL(OIDC_CONFIG.AUTHORIZATION_ENDPOINT);
    authUrl.searchParams.append('response_type', 'code');
    authUrl.searchParams.append('client_id', OIDC_CONFIG.CLIENT_ID);
    authUrl.searchParams.append('redirect_uri', OIDC_CONFIG.REDIRECT_URI);
    authUrl.searchParams.append('scope', OIDC_CONFIG.SCOPE);
    authUrl.searchParams.append('state', state);
    authUrl.searchParams.append('nonce', nonce);

    window.location.href = authUrl.toString();
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h1>React OIDC SPA</h1>
      {isAuthenticated ? (
        <div>
          <p>Welcome, {userProfile?.name || userProfile?.preferred_username || userProfile?.sub}!</p>
          <h3>User Profile:</h3>
          <pre style={{ backgroundColor: '#f0f0f0', padding: '10px', borderRadius: '5px' }}>
            {JSON.stringify(userProfile, null, 2)}
          </pre>
          <button onClick={logout} style={{ padding: '10px 20px', fontSize: '16px', cursor: 'pointer' }}>
            Logout
          </button>
        </div>
      ) : (
        <div>
          <p>You are not authenticated.</p>
          <button onClick={handleLoginRedirect} style={{ padding: '10px 20px', fontSize: '16px', cursor: 'pointer' }}>
            Login with OIDC
          </button>
        </div>
      )}
    </div>
  );
};

const Callback = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { login } = React.useContext(AuthContext);

  useEffect(() => {
    const handleCallback = async () => {
      const params = new URLSearchParams(location.search);
      const code = params.get('code');
      const state = params.get('state');
      const error = params.get('error');
      const errorDescription = params.get('error_description');

      if (error) {
        console.error('OIDC Error:', error, errorDescription);
        alert(`Authentication failed: ${errorDescription || error}`);
        navigate('/');
        return;
      }

      if (!code || !state) {
        console.error('Missing code or state in callback URL.');
        navigate('/');
        return;
      }

      const storedState = localStorage.getItem('oidc_state');
      if (state !== storedState) {
        console.error('State mismatch! Possible CSRF attack.');
        alert('Authentication failed: State mismatch.');
        navigate('/');
        return;
      }
      localStorage.removeItem('oidc_state'); // Clear state after validation

      try {
        // Exchange authorization code for tokens
        const tokenResponse = await fetch(OIDC_CONFIG.TOKEN_ENDPOINT, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            grant_type: 'authorization_code',
            code: code,
            redirect_uri: OIDC_CONFIG.REDIRECT_URI,
            client_id: OIDC_CONFIG.CLIENT_ID,
          }).toString(),
        });

        if (!tokenResponse.ok) {
          const errorData = await tokenResponse.json();
          throw new Error(`Token exchange failed: ${errorData.error_description || errorData.error}`);
        }

        const tokenData = await tokenResponse.json();
        const idToken = tokenData.id_token;
        const accessToken = tokenData.access_token;

        if (!idToken) {
          throw new Error('ID Token not received.');
        }

        // Decode ID Token to get user profile
        const userProfile = decodeJwt(idToken);
        const storedNonce = localStorage.getItem('oidc_nonce');

        if (userProfile && userProfile.nonce !== storedNonce) {
            console.error('Nonce mismatch! Possible replay attack.');
            alert('Authentication failed: Nonce mismatch.');
            navigate('/');
            return;
        }
        localStorage.removeItem('oidc_nonce'); // Clear nonce after validation

        if (userProfile) {
          login(idToken, accessToken, userProfile);
          navigate('/'); // Redirect to home page after successful login
        } else {
          throw new Error('Failed to decode ID Token or get user profile.');
        }

      } catch (error) {
        console.error('Authentication process failed:', error);
        alert(`Authentication failed: ${error.message}`);
        navigate('/');
      }
    };

    handleCallback();
  }, [location, navigate, login]);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h2>Processing authentication...</h2>
      <p>Please wait while we securely log you in.</p>
    </div>
  );
};

const App = () => {
  return (
    <Router>
      <AuthProvider>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/callback" element={<Callback />} />
        </Routes>
      </AuthProvider>
    </Router>
  );
};

export default App;